const fs = require('fs');

const configPath = '/files/message_config.json';
const logsPath = '/files/logs.jsonl';
const assinaturaPath = '/files/signature.html';
const extrasPath = '/files/contacts_added.json';
const gruposPath = '/files/groups.json';
const envioConfigPath = '/files/send_config.json';
const filaPath = '/files/queue.json';
const enviadosPath = '/files/sent_campaigns.json';
const acaoUrl = 'http://localhost:5678/webhook/mala-direta-acao';

function escapeHtml(value) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}

function htmlToText(value) {
  return String(value ?? '')
    .replace(/^\uFEFF/, '')
    .replace(/<br\s*\/?\s*>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<p[^>]*>/gi, '')
    .replace(/<[^>]+>/g, '')
    .replaceAll('&nbsp;', ' ')
    .replaceAll('&lt;', '<')
    .replaceAll('&gt;', '>')
    .replaceAll('&amp;', '&')
    .replaceAll('&quot;', '"')
    .trim();
}

function ensureFiles() {
  if (!fs.existsSync('/files')) {
    throw new Error('A pasta /files não existe dentro do container. Verifique o volume C:/n8n/files:/files no docker-compose.yml.');
  }
  if (!fs.existsSync(configPath)) {
    fs.writeFileSync(configPath, JSON.stringify({
      assunto: 'Comunicado Vesper',
      mensagem_texto: 'Boa tarde,\n\nEscreva aqui a mensagem que será enviada.\n\nAtenciosamente,',
      atualizado_em: new Date().toISOString()
    }, null, 2), 'utf8');
  }
  if (!fs.existsSync(logsPath)) fs.writeFileSync(logsPath, '', 'utf8');
  if (!fs.existsSync(extrasPath)) fs.writeFileSync(extrasPath, '[]', 'utf8');
  if (!fs.existsSync(gruposPath)) fs.writeFileSync(gruposPath, '{}', 'utf8');
  if (!fs.existsSync(envioConfigPath)) fs.writeFileSync(envioConfigPath, JSON.stringify({parcelado_ativo:true,lote_quantidade:50,intervalo_valor:12,intervalo_unidade:'horas'}, null, 2), 'utf8');
  if (!fs.existsSync(filaPath)) fs.writeFileSync(filaPath, '[]', 'utf8');
  if (!fs.existsSync(enviadosPath)) fs.writeFileSync(enviadosPath, '{}', 'utf8');
}

function readJson(path, fallback) {
  try { return JSON.parse(fs.readFileSync(path, 'utf8').replace(/^\uFEFF/, '')); } catch { return fallback; }
}

ensureFiles();

const config = readJson(configPath, {
  assunto: 'Comunicado Vesper',
  mensagem_texto: 'Boa tarde,\n\nEscreva aqui a mensagem que será enviada.\n\nAtenciosamente,'
});

let mensagemTexto = '';
if (typeof config.mensagem_texto === 'string' && config.mensagem_texto.trim()) mensagemTexto = config.mensagem_texto;
else if (typeof config.mensagem === 'string' && config.mensagem.trim()) mensagemTexto = htmlToText(config.mensagem);
else mensagemTexto = 'Boa tarde,\n\nEscreva aqui a mensagem que será enviada.\n\nAtenciosamente,';

const assinaturaExiste = fs.existsSync(assinaturaPath);
let assinaturaPreview = '';
try {
  assinaturaPreview = fs.readFileSync(assinaturaPath, 'utf8')
    .replace(/^\uFEFF/, '')
    .replace(/<meta[^>]*>/gi, '')
    .replace(/<link[^>]*>/gi, '')
    .replace(/href=["']www\.vesper\.ind\.br["']/gi, 'href="http://www.example.com"');
} catch {
  assinaturaPreview = '<p>Atenciosamente,</p><strong style="color:red;font-size:20px">Empresa EX LTDA</strong><br><a href="mailto:sender@example.com">sender@example.com</a><br><a href="http://www.example.com">www.example.com</a>';
}

const extras = Array.isArray(readJson(extrasPath, [])) ? readJson(extrasPath, []) : [];
const grupos = readJson(gruposPath, {});
const envioConfig = readJson(envioConfigPath, {parcelado_ativo:true,lote_quantidade:50,intervalo_valor:12,intervalo_unidade:'horas'});
if (envioConfig.intervalo_valor === undefined && envioConfig.intervalo_horas !== undefined) envioConfig.intervalo_valor = envioConfig.intervalo_horas;
if (!envioConfig.intervalo_unidade) envioConfig.intervalo_unidade = 'horas';
const enviadosCampanhas = readJson(enviadosPath, {});
function hashCampanhaTexto(assunto, mensagem) {
  const texto = String(assunto || '') + '\n' + String(mensagem || '');
  let h = 2166136261;
  for (let i = 0; i < texto.length; i++) {
    h ^= texto.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}
function campaignIdLocal(assunto, mensagem) {
  return hashCampanhaTexto(String(assunto || '') + '\n' + String(mensagem || ''), '');
}
const campanhaAtualId = campaignIdLocal(config.assunto || 'Comunicado Vesper', mensagemTexto);
const enviadosCampanhaAtual = enviadosCampanhas[campanhaAtualId]?.emails || {};
const totalJaEnviadosCampanha = Object.keys(enviadosCampanhaAtual).length;
const anexosPadrao = Array.isArray(config.anexos_base64) ? config.anexos_base64 : [];
const totalAnexosPadrao = anexosPadrao.length;
const filaEnvio = Array.isArray(readJson(filaPath, [])) ? readJson(filaPath, []) : [];
const totalFilaCampanhas = filaEnvio.length;
const totalFilaContatos = filaEnvio.reduce((s,c)=>s+(Array.isArray(c.contatos)?c.contatos.length:0),0);
const proximoLote = filaEnvio.map(c=>c.proxima_execucao).filter(Boolean).sort()[0] || 'Nenhum lote pendente';
const gruposNomes = Object.keys(grupos || {}).sort((a,b)=>a.localeCompare(b,'pt-BR'));
const gruposOptions = gruposNomes.map(g => `<option value="${escapeHtml(g)}">${escapeHtml(g)}</option>`).join('');
const gruposCards = gruposNomes.map(g => `<button type="button" class="group-card group-card-btn" data-grupo-card="${escapeHtml(g)}"><div><b>${escapeHtml(g)}</b><small>${(Array.isArray(grupos[g]) ? grupos[g].length : 0)} contatos salvos</small></div><span class="chip">abrir</span></button>`).join('') || '<div class="group-card"><div><b>Nenhum grupo criado ainda</b><small>Crie um grupo ou importe contatos para organizar os envios.</small></div></div>';
const logs = (() => {
  try {
    const content = fs.readFileSync(logsPath, 'utf8').trim();
    if (!content) return [];
    return content.split(/\r?\n/).filter(Boolean).map(line => {
      try { return JSON.parse(line); } catch { return null; }
    }).filter(Boolean).reverse();
  } catch { return []; }
})();


const rows = $input.all();
const clientesMap = new Map();

function garantirCliente(empresa, email, origem) {
  empresa = String(empresa || '').trim();
  email = String(email || '').trim().toLowerCase();
  if (!empresa || !email || !email.includes('@')) return null;
  if (!clientesMap.has(email)) clientesMap.set(email, { empresa, email, origem, grupos: [] });
  const c = clientesMap.get(email);
  if ((!c.empresa || c.empresa === email.split('@')[0]) && empresa) c.empresa = empresa;
  if (origem === 'manual') c.origem = 'manual';
  return c;
}

function addGrupo(email, grupo) {
  email = String(email || '').trim().toLowerCase();
  grupo = String(grupo || '').trim();
  if (!email || !grupo || !clientesMap.has(email)) return;
  const c = clientesMap.get(email);
  if (!c.grupos.includes(grupo)) c.grupos.push(grupo);
}

for (const item of rows) {
  const row = item.json || {};
  garantirCliente(row.empresa || row.Empresa || row.nome || row.Nome || row.cliente || row.Cliente || '', row.email || row.Email || row.e_mail || row['e-mail'] || '', 'planilha');
}

for (const item of extras) {
  const c = garantirCliente(item.empresa || item.nome || '', item.email || '', 'manual');
  if (c && item.grupo) addGrupo(c.email, item.grupo);
}

for (const [grupo, emails] of Object.entries(grupos || {})) {
  for (const email of (Array.isArray(emails) ? emails : [])) {
    if (clientesMap.has(String(email).toLowerCase())) addGrupo(email, grupo);
  }
}

const clientes = [...clientesMap.values()].sort((a, b) => a.empresa.localeCompare(b.empresa, 'pt-BR'));

const totalClientes = clientes.length;
const totalExtras = extras.length;
const totalGrupos = gruposNomes.length;
const totalSucesso = logs.filter(l => l.status === 'sucesso').length;
const totalErro = logs.filter(l => l.status === 'erro').length;
const ultimaAcao = logs[0]?.data_hora || 'Nenhum envio ainda';
const logsRecentes = logs.slice(0, 8);

const clienteRows = clientes.map((c, idx) => {
  const value = `${c.email}||${c.empresa}`;
  const badge = c.origem === 'manual' ? '<span class="badge-new">adicionado</span>' : '';
  const gruposTxt = (c.grupos || []).join(', ');
  const gruposData = (c.grupos || []).map(g => g.toLowerCase()).join('|');
  return `<tr class="linha-cliente" data-email="${escapeHtml(c.email)}" data-original-order="${idx}" data-groups="${escapeHtml(gruposData)}" data-search="${escapeHtml((c.empresa + ' ' + c.email + ' ' + gruposTxt).toLowerCase())}"><td><input type="checkbox" name="selecionados" value="${escapeHtml(value)}"></td><td>${idx + 1}</td><td>${escapeHtml(c.empresa)} ${badge}</td><td>${escapeHtml(c.email)}</td><td>${escapeHtml(gruposTxt || 'Geral')}</td></tr>`;
}).join('');

const logRows = logsRecentes.map(log => `<tr><td>${escapeHtml(log.data_hora)}</td><td>${escapeHtml(log.empresa)}</td><td>${escapeHtml(log.email)}</td><td><span class="status ${log.status === 'sucesso' ? 'ok' : 'erro'}">${log.status === 'sucesso' ? 'enviado' : 'erro'}</span></td></tr>`).join('');

const html = `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Mala Direta Vesper</title><style>
