-size:22px}.modal-top{padding-right:60px;margin-bottom:18px}.modal-tag{display:inline-flex;padding:8px 12px;border-radius:999px;background:#f8fbff;border:1px solid var(--line);font-size:12px;font-weight:950;text-transform:uppercase;letter-spacing:.05em;color:#45617e;margin-bottom:12px}.modal-title{font-size:30px;font-weight:950;letter-spacing:-.04em;margin:0 0 7px}.field{margin-top:16px}label{display:block;font-weight:900;font-size:15px;margin-bottom:8px}input[type="text"],input[type="email"],input[type="number"],textarea{width:100%;border:1px solid var(--line2);background:#fff;color:var(--text);border-radius:16px;padding:14px 16px;font-size:16px;outline:none;transition:.15s ease}input:focus,textarea:focus{border-color:#60a5fa;box-shadow:0 0 0 4px rgba(96,165,250,.18)}textarea{min-height:220px;resize:vertical;line-height:1.55}.row{display:grid;grid-template-columns:1fr 1fr;gap:14px}.help{color:var(--muted);font-size:13px;line-height:1.5;margin-top:8px}.actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:18px}.confirm{display:flex;gap:10px;align-items:flex-start;margin-top:14px;font-weight:800;color:#334155}.confirm input{margin-top:3px}.dropzone{margin-top:10px;border:2px dashed #bfcee2;background:#f8fbff;border-radius:18px;padding:18px;text-align:center;transition:.15s ease;outline:none}.dropzone:hover,.dropzone:focus,.dropzone.dragover{border-color:#60a5fa;background:#eff6ff}.drop-main{font-weight:950;font-size:15px;margin-bottom:4px}.drop-sub{color:var(--muted);font-size:13px;line-height:1.45}.drop-list{margin-top:10px;text-align:left;color:#334155;font-size:13px}.file-item{display:flex;justify-content:space-between;gap:10px;padding:9px 10px;border:1px solid var(--line);border-radius:12px;background:#fff;margin-top:8px}.file-remove{background:transparent;border:0;color:var(--red);font-weight:950;cursor:pointer;box-shadow:none;padding:0}.hide{position:absolute!important;left:-9999px!important;width:1px!important;height:1px!important;opacity:0!important;overflow:hidden!important}.search-box{display:grid;grid-template-columns:1fr auto auto;gap:10px;align-items:end}.contacts-wrap{margin-top:12px;max-height:340px;overflow:auto;border:1px solid var(--line);border-radius:16px;background:#fff}.signature-preview{margin-top:14px;border:1px solid var(--line);background:#f8fbff;border-radius:18px;padding:14px;max-height:260px;overflow:auto}.dot{display:inline-block;width:10px;height:10px;border-radius:50%;background:${assinaturaExiste ? '#16a34a' : '#dc2626'};margin-right:8px}.signature-alert{margin-top:14px;padding:12px 14px;border-radius:16px;background:#eff6ff;color:#1d4ed8;font-weight:900}.alert{position:fixed;inset:0;background:rgba(20,33,53,.42);display:none;align-items:center;justify-content:center;z-index:99;padding:20px}.alert.open{display:flex}.alert-card{width:min(620px,100%);background:#fff;border:1px solid var(--line);border-radius:28px;padding:30px;box-shadow:0 30px 90px rgba(18,34,64,.28)}.alert-icon{width:62px;height:62px;border-radius:22px;display:flex;align-items:center;justify-content:center;font-size:30px;margin-bottom:18px}.alert-icon.ok{background:#ecfdf3;color:#16a34a}.alert-icon.erro{background:#fef2f2;color:#dc2626}.alert-card h2{font-size:30px}.alert-card p{font-size:17px;line-height:1.55;color:#5f6f86;margin-top:8px}@media(max-width:1040px){.hero-grid,.row{grid-template-columns:1fr}.main-actions{grid-template-columns:repeat(2,1fr)}.stats{grid-template-columns:repeat(2,1fr)}}@media(max-width:720px){.wrap{padding:14px}.main-actions,.search-box{grid-template-columns:1fr}.brand{align-items:flex-start}.brand-icon{width:58px;height:58px}.hero{padding:20px;border-radius:24px}h1{font-size:30px}.modal-box{border-radius:24px;padding:20px}button{width:100%}}

/* BOTÕES QUE ABREM MODAIS POR LINK - SEM DEPENDER DE JAVASCRIPT */
a.btn-link,
a.btn-link:link,
a.btn-link:visited{
  display:inline-flex;
  align-items:center;
  justify-content:center;
  gap:8px;
  min-height:46px;
  padding:13px 17px;
  border-radius:16px;
  border:0;
  font-size:15px;
  font-weight:900;
  line-height:1;
  text-align:center;
  text-decoration:none;
  cursor:pointer;
  box-shadow:0 12px 24px rgba(18,34,64,.13);
  transition:transform .12s ease, box-shadow .12s ease, filter .12s ease;
}
a.btn-link:hover{
  text-decoration:none;
  transform:translateY(-1px);
  filter:brightness(1.02);
  box-shadow:0 16px 30px rgba(18,34,64,.16);
}
a.btn-link:active{
  transform:translateY(0);
  box-shadow:0 8px 18px rgba(18,34,64,.13);
}
a.btn-link.btn-blue{background:var(--blue);color:#fff}
a.btn-link.btn-purple{background:var(--purple);color:#fff}
a.btn-link.btn-green{background:var(--green);color:#fff}
a.btn-link.btn-orange{background:var(--orange);color:#fff}
a.btn-link.secondary{
  background:#fff;
  color:#28415f;
  border:1px solid var(--line);
  box-shadow:none;
}
.action-card>a.btn-link{
  width:100%;
  margin-top:18px;
}
.action-card .actions{
  display:grid;
  grid-template-columns:repeat(3,minmax(0,1fr));
  gap:8px;
  margin-top:18px;
}
.action-card .actions a.btn-link{
  width:100%;
  padding:12px 10px;
  font-size:13px;
  min-height:42px;
}
.modal-close,
.modal-close:link,
.modal-close:visited{
  position:absolute;
  right:18px;
  top:18px;
  width:44px;
  height:44px;
  border-radius:15px;
  background:#fff;
  color:#475569;
  border:1px solid var(--line);
  box-shadow:none;
  font-size:22px;
  font-weight:900;
  text-decoration:none;
  display:flex;
  align-items:center;
  justify-content:center;
}
select{
  width:100%;
  border:1px solid var(--line2);
  background:#fff;
  color:var(--text);
  border-radius:16px;
  padding:14px 16px;
  font-size:16px;
  outline:none;
}
select:focus{
  border-color:#60a5fa;
  box-shadow:0 0 0 4px rgba(96,165,250,.18);
}
@media(max-width:720px){
  a.btn-link{width:100%}
  .action-card .actions{grid-template-columns:1fr}
}


