 function ordenarGrupoPrimeiro(grupo){
   const set=emailsDoGrupo(grupo);
   const ordenadas=[...rows].sort((a,b)=>{
     const aIn=set.has(emailDaLinha(a)) ? 0 : 1;
     const bIn=set.has(emailDaLinha(b)) ? 0 : 1;
     if(aIn!==bIn) return aIn-bIn;
     return Number(a.dataset.originalOrder||0)-Number(b.dataset.originalOrder||0);
   });
   ordenadas.forEach((row,idx)=>{
     tbody.appendChild(row);
