let zonaAtivaParaColar = null;

function atualizarListaArquivos(input, list){
  list.innerHTML='';
  const files=Array.from(input.files||[]);
  if(!files.length){
    list.innerHTML='<div class="file-item" style="opacity:.75">Nenhum arquivo selecionado.</div>';
    return;
  }
  files.forEach((file,index)=>{
    const item=document.createElement('div');
    item.className='file-item';
    const left=document.createElement('div');
    const size=file.size?' - '+Math.max(1,Math.round(file.size/1024))+' KB':'';
    left.textContent=file.name+size;
    const rm=document.createElement('button');
    rm.type='button';
    rm.className='file-remove';
    rm.textContent='remover';
    rm.addEventListener('click',()=>{
      const next=new DataTransfer();
      Array.from(input.files||[]).forEach((f,i)=>{if(i!==index)next.items.add(f)});
      input.files=next.files;
      atualizarListaArquivos(input,list);
    });
    item.appendChild(left);
    item.appendChild(rm);
    list.appendChild(item);
  });
}

function adicionarArquivosNoInput(input, list, fileList){
  if(!input||!list||!fileList||!fileList.length)return false;
  const next=new DataTransfer();
  const existentes=Array.from(input.files||[]);
  const chaves=new Set(existentes.map(f=>f.name+'|'+f.size+'|'+f.lastModified));
  existentes.forEach(f=>next.items.add(f));
  Array.from(fileList).forEach(file=>{
    const chave=file.name+'|'+file.size+'|'+file.lastModified;
    if(!chaves.has(chave)){
      next.items.add(file);
      chaves.add(chave);
    }
  });
  input.files=next.files;
  atualizarListaArquivos(input,list);
  return true;
}

function zonaVisivelPadrao(){
  const alvo = window.location.hash ? document.querySelector(window.location.hash + ' .dropzone') : null;
  if(alvo) return alvo;
  return Array.from(document.querySelectorAll('.modal:target .dropzone, .modal.open .dropzone')).find(Boolean) || null;
}

function setupDropzone(zoneId,inputId,listId){
  const zone=document.getElementById(zoneId);
  const input=document.getElementById(inputId);
  const list=document.getElementById(listId);
  if(!zone||!input||!list)return;

  zone.dataset.inputId=inputId;
  zone.dataset.listId=listId;

  document.querySelectorAll('[data-input="'+inputId+'"]').forEach(btn=>btn.addEventListener('click',()=>input.click()));

  input.addEventListener('change',()=>atualizarListaArquivos(input,list));

  zone.addEventListener('mouseenter',()=>{zonaAtivaParaColar=zone; try{zone.focus();}catch(e){} });
  zone.addEventListener('mousemove',()=>{zonaAtivaParaColar=zone;});
  zone.addEventListener('focus',()=>{zonaAtivaParaColar=zone;});
  zone.addEventListener('click',()=>{zonaAtivaParaColar=zone; zone.focus();});
  zone.addEventListener('dragover',e=>{e.preventDefault();zonaAtivaParaColar=zone;zone.classList.add('dragover')});
  zone.addEventListener('dragleave',()=>zone.classList.remove('dragover'));
  zone.addEventListener('drop',e=>{
    e.preventDefault();
    zone.classList.remove('dragover');
    zonaAtivaParaColar=zone;
    if(e.dataTransfer?.files?.length)adicionarArquivosNoInput(input,list,e.dataTransfer.files);
  });
  atualizarListaArquivos(input,list);
}

let ultimaColagemArquivos = '';
document.addEventListener('paste',e=>{
  const items=Array.from(e.clipboardData?.items||[]);
  const files=items.filter(item=>item.kind==='file').map(item=>item.getAsFile()).filter(Boolean);
  if(!files.length)return;

  const assinatura = files.map(f=>f.name+'|'+f.size+'|'+f.type).join(';');
  const agora = Date.now();
  if(window.__ultimaColagemAssinatura === assinatura && window.__ultimaColagemQuando && (agora - window.__ultimaColagemQuando) < 800){
    e.preventDefault();
    e.stopImmediatePropagation();
    return;
  }
  window.__ultimaColagemAssinatura = assinatura;
  window.__ultimaColagemQuando = agora;

  const zone=zonaAtivaParaColar || zonaVisivelPadrao();
  if(!zone)return;

  const input=document.getElementById(zone.dataset.inputId);
  const list=document.getElementById(zone.dataset.listId);
  if(adicionarArquivosNoInput(input,list,files)){
    e.preventDefault();
    e.stopImmediatePropagation();
  }
});

function fileToBase64(file){
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onload=()=>{
      const result=String(reader.result||'');
      resolve({fileName:file.name,mimeType:file.type||'application/octet-stream',size:file.size,data:result.split(',')[1]||''});
    };
    reader.onerror=reject;
    reader.readAsDataURL(file);
  });
}

async function arquivosDoInput(id){
  const files=Array.from(document.getElementById(id)?.files||[]);
  const total=files.reduce((s,f)=>s+f.size,0);
  if(total>12*1024*1024)throw new Error('Os anexos estão muito grandes. Use até 12 MB por envio.');
  const saida=[];
  for(const f of files)saida.push(await fileToBase64(f));
  return saida;
}

async function enviarPayload(payload){
  const res=await fetch('${acaoUrl}',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify(payload)
  });
  if(!res.ok){
    let body='';
    try{body=await res.text()}catch{}
    throw new Error('HTTP '+res.status+(body?' - '+body.slice(0,180):''));
  }
}

function bloquearSubmit(e, form){
  if(e) e.preventDefault();
