  return false;
}
window.bloquearSubmit = bloquearSubmit;

async function enviarFormulario(form){
  if(!form) return false;
  if(form.dataset.enviando === '1') return false;
  form.dataset.enviando = '1';

  const botoes = Array.from(form.querySelectorAll('button[type="submit"]'));
  const textosOriginais = botoes.map(b => b.textContent);
  botoes.forEach(b => { b.disabled = true; b.textContent = 'Enviando...'; });

  try{
    const action=form.dataset.action;
    const fd=new FormData(form);
    const payload={acao:action};

    for(const [k,v] of fd.entries()){
      if(k==='selecionados'){
        if(!payload.selecionados)payload.selecionados=[];
        payload.selecionados.push(v);
      }else{
        payload[k]=v;
      }
    }

    if(action==='salvar')payload.anexos_base64=await arquivosDoInput('anexo_mensagem');
    if(action==='teste_unico')payload.anexos_base64=await arquivosDoInput('anexo_teste');
    if(action==='enviar_destinatarios')payload.anexos_base64=await arquivosDoInput('anexo_envio');

    await enviarPayload(payload);

    if(action==='salvar')mostrarAviso('Mensagem salva','Pronto. A mensagem foi salva.');
    else if(action==='adicionar_contato')mostrarAviso('Contato salvo','Pronto. O contato foi enviado para salvar. Atualize o painel em alguns segundos para aparecer na lista.');
    else if(action==='criar_grupo'||action==='salvar_grupo_inteligente')mostrarAviso('Grupo salvo','Pronto. O grupo foi atualizado. Atualize o painel em alguns segundos para ver a lista.');
    else if(action==='renomear_grupo')mostrarAviso('Grupo renomeado','Pronto. O grupo foi renomeado. Atualize o painel para ver a mudança.');
    else if(action==='excluir_grupo')mostrarAviso('Grupo excluído','Pronto. O grupo foi excluído. Os contatos continuam salvos.');
    else if(action==='salvar_configuracao')mostrarAviso('Configuração salva','Pronto. A configuração de envio parcelado foi salva.');
    else if(action==='teste_unico')mostrarAviso('Teste enviado','O teste foi enviado uma única vez. Confira a caixa de entrada.');
    else mostrarAviso('Envio iniciado','A mensagem foi enviada para o n8n. Se houver parcelamento, os próximos lotes ficarão na fila.');
  }catch(err){
    mostrarAviso('Não foi possível enviar','Detalhe: '+(err.message||err),'erro');
  }finally{
    form.dataset.enviando = '0';
    botoes.forEach((b,i) => { b.disabled = false; b.textContent = textosOriginais[i] || 'Enviar'; });
  }
  return false;
}
window.enviarFormulario = enviarFormulario;


let contatosImportadosAtuais = [];
function nomePeloEmail(email){return String(email||'').split('@')[0].replace(/[._-]+/g,' ').trim()||String(email||'').split('@')[0]}
function limparNomeContato(txt){return String(txt||'').replace(/[<>]/g,' ').replace(/\\b(e-?mail|email|contato|comercial|compras|financeiro|telefone|tel|cel|whatsapp|site|www)\\b\\s*:*/gi,' ').replace(/\\s+/g,' ').trim()}
function extrairContatosDoTexto(texto){
  const emailRe=/[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,}/ig;
  const linhas=String(texto||'').replace(/\\r/g,'\\n').split('\\n');
  const encontrados=[];
  const usados=new Set();
  function add(nome,email){email=String(email||'').toLowerCase().trim();nome=limparNomeContato(nome)||nomePeloEmail(email);if(!email||!email.includes('@')||usados.has(email))return;usados.add(email);encontrados.push({empresa:nome,email})}
  for(let i=0;i<linhas.length;i++){
    const linha=linhas[i]||'';
    const emails=[...linha.matchAll(emailRe)].map(m=>m[0]);
    if(!emails.length)continue;
    for(const email of emails){
      let antes=linha.slice(0,linha.toLowerCase().indexOf(email.toLowerCase()));
      let depois=linha.replace(email,' ');
      let nome=limparNomeContato(antes);
      if(!nome || nome.length<2){
        const partes=linha.split(/\\t|;|,/).map(x=>x.trim()).filter(Boolean);
        const semEmail=partes.filter(p=>!p.toLowerCase().includes(email.toLowerCase())&&!p.includes('@'));
        nome=limparNomeContato(semEmail[0]||'');
      }
      if(!nome || nome.length<2){
        for(let j=i-1;j>=Math.max(0,i-3);j--){
          const cand=limparNomeContato(linhas[j]);
          if(cand && !cand.includes('@') && cand.length>1 && cand.length<80 && !/^\\+?\\d|telefone|tel|cel|whatsapp|www|http/i.test(cand)){nome=cand;break}
        }
      }
      add(nome,email);
    }
  }
  const soltos=String(texto||'').match(emailRe)||[];
  for(const email of soltos)add('',email);
  return encontrados;
}
function renderPreviewImportacao(){
  const tbody=document.getElementById('tbody_importacao');const resumo=document.getElementById('resumo_importacao');const box=document.getElementById('preview_importacao');
  tbody.innerHTML='';
  contatosImportadosAtuais.forEach((c,i)=>{const tr=document.createElement('tr');tr.innerHTML='<td>'+(i+1)+'</td><td><input data-edit-empresa="'+i+'" value="'+escapeHtmlClient(c.empresa)+'" style="width:100%;border:1px solid #dbe5f2;border-radius:10px;padding:8px"></td><td>'+escapeHtmlClient(c.email)+'</td><td>'+(c.status||'novo / verificar')+'</td>';tbody.appendChild(tr)});document.querySelectorAll('[data-edit-empresa]').forEach(inp=>inp.addEventListener('input',()=>{contatosImportadosAtuais[Number(inp.dataset.editEmpresa)].empresa=inp.value}));
  resumo.textContent=contatosImportadosAtuais.length?('Foram encontrados '+contatosImportadosAtuais.length+' contatos válidos. Duplicados foram removidos.'):'Nenhum e-mail válido encontrado.';
  box.style.display='block';
}
function escapeHtmlClient(v){return String(v||'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;')}
async function lerArquivoTexto(file){return await file.text()}
async function adicionarArquivosImportacao(files){
  let atual=document.getElementById('import_texto').value||'';
  const nomes=[];
  for(const file of Array.from(files||[])){
    nomes.push(file.name);
    if(/\\.(csv|txt|vcf)$/i.test(file.name)){
      atual += '\\n\\n' + await lerArquivoTexto(file);
    }else{
      mostrarAviso('Arquivo não importado','Use CSV, TXT ou VCF. Para Excel, copie as linhas da planilha e cole no campo de texto, ou salve como CSV.','erro');
    }
  }
  document.getElementById('import_texto').value=atual.trim();
  document.getElementById('lista_importar').textContent=nomes.length?nomes.join(', '):'Nenhum arquivo selecionado.';
}
function setupImportacao(){
  const area=document.getElementById('zona_importar');
  const input=document.getElementById('arquivo_importar');
  const btn=document.getElementById('btn_arquivo_importar');
  if(!area)return;

  btn?.addEventListener('click',()=>input.click());
  input?.addEventListener('change',async()=>adicionarArquivosImportacao(input.files));

  area.addEventListener('dragover',e=>{
    e.preventDefault();
    area.classList.add('dragover');
  });

  area.addEventListener('dragleave',()=>area.classList.remove('dragover'));

  area.addEventListener('drop',async e=>{
    e.preventDefault();
    area.classList.remove('dragover');
    await adicionarArquivosImportacao(e.dataTransfer.files);
  });

  document.getElementById('btn_prever_importacao')?.addEventListener('click',()=>{
    contatosImportadosAtuais=extrairContatosDoTexto(document.getElementById('import_texto').value);
    renderPreviewImportacao();
  });

  document.getElementById('btn_salvar_importados')?.addEventListener('click',async()=>{
    try{
      if(!contatosImportadosAtuais.length){
        contatosImportadosAtuais=extrairContatosDoTexto(document.getElementById('import_texto').value);
        renderPreviewImportacao();
      }

      if(!contatosImportadosAtuais.length){
        throw new Error('Nenhum e-mail válido encontrado.');
      }

      const grupoNovo=document.getElementById('import_grupo').value.trim();
      const grupoExistente=document.getElementById('import_grupo_existente').value.trim();

      await enviarPayload({
        acao:'importar_contatos',
        grupo:grupoNovo||grupoExistente,
        contatos:contatosImportadosAtuais
      });

      mostrarAviso(
        'Contatos enviados para salvar',
        'Os contatos foram enviados para o n8n. Atualize o painel em alguns segundos. O envio continua sendo feito pelo botão Enviar.'
      );
    }catch(err){
      mostrarAviso('Não foi possível importar','Detalhe: '+(err.message||err),'erro');
    }
  });
}


function smartTextToHtml(text){
  return String(text||'').trim().split(/\\n{2,}/).filter(Boolean).map(p=>'<p>'+escapeHtmlClient(p).replace(/\\n/g,'<br>')+'</p>').join('\\n');
}

function smartEnsureAfter(el, id, html){
  if(!el) return null;
  let existing=document.getElementById(id);
  if(existing) return existing;
  const wrap=document.createElement('div');
  wrap.innerHTML=html.trim();
  const node=wrap.firstElementChild;
  el.insertAdjacentElement('afterend',node);
  return node;
}

function smartContarMarcados(modalId){
  return Array.from(document.querySelectorAll(modalId+' input[type="checkbox"][name="selecionados"]')).filter(c=>c.checked).length;
}

function smartifyMensagem(){
  const modal=document.getElementById('modal_mensagem');
  if(!modal)return;
  const assunto=modal.querySelector('input[name="assunto"]');
