    return [{ json: { tipo: 'enviar', modo: 'direto', origem: 'teste_unico', responder: false, destinatarios_diretos: [{ empresa: nome_teste, email: email_teste }], filtro: '', limite: 0, campanha_id: 'teste' }, binary }];
  }

  if (acao === 'enviar_destinatarios') {
    if (body.confirmar !== 'sim') return [{ json: { tipo: 'responder', status: 'erro', mensagem: 'Envio não confirmado.' } }];
    const selecionados = normalizeArray(body.selecionados).map(v => {
      const [email, ...rest] = String(v || '').split('||');
      return { email: String(email || '').trim().toLowerCase(), empresa: rest.join('||').trim() || String(email || '').split('@')[0] };
    });
    let destinatarios_diretos = juntarUnicos(selecionados);
    if (!destinatarios_diretos.length) return [{ json: { tipo: 'responder', status: 'erro', mensagem: 'Nenhum contato marcado.' } }];

    const envioCfg = getEnvioConfig();
    const configAtual = readJson(configPath, { assunto: 'Comunicado Vesper', mensagem_texto: '' });
    const anexos_base64 = juntarAnexosPadrao(configAtual, body);
    const campId = campanhaId(String(configAtual.assunto || 'Comunicado Vesper'), String(configAtual.mensagem_texto || configAtual.mensagem || ''));
    const permitirReenvio = !(String(body.evitar_reenvio || '').toLowerCase() === 'sim') || envioCfg.protecao_global === false;
    const antesFiltro = destinatarios_diretos.length;
    destinatarios_diretos = filtrarJaEnviados(destinatarios_diretos, campId, permitirReenvio);
    if (!destinatarios_diretos.length) return [{ json: { tipo: 'responder', status: 'erro', mensagem: `Todos os ${antesFiltro} contato(s) marcados já receberam esta campanha. Para reenviar, desmarque a proteção anti-reenvio.` } }];

    if (envioCfg.parcelado_ativo && envioCfg.lote_quantidade > 0 && destinatarios_diretos.length > envioCfg.lote_quantidade) {
      const primeiroLote = destinatarios_diretos.slice(0, envioCfg.lote_quantidade);
      const restantes = destinatarios_diretos.slice(envioCfg.lote_quantidade);
      const fila = Array.isArray(readJson(filaPath, [])) ? readJson(filaPath, []) : [];
      fila.push({
        id: 'camp_' + Date.now() + '_' + Math.random().toString(36).slice(2,8),
        campanha_id: campId,
        criado_em: new Date().toISOString(),
        proxima_execucao: dataDepois(envioCfg.intervalo_valor, envioCfg.intervalo_unidade),
        lote_quantidade: envioCfg.lote_quantidade,
        intervalo_valor: envioCfg.intervalo_valor,
        intervalo_unidade: envioCfg.intervalo_unidade,
        assunto_snapshot: String(configAtual.assunto || 'Comunicado Vesper'),
        mensagem_texto_snapshot: String(configAtual.mensagem_texto || configAtual.mensagem || ''),
        anexos_base64,
        contatos: restantes
      });
      writeJson(filaPath, fila);
      destinatarios_diretos = primeiroLote;
    }

    const binary = await anexosParaBinary.call(this, anexos_base64);
    return [{ json: { tipo: 'enviar', modo: 'direto', origem: 'selecionados', responder: false, destinatarios_diretos, filtro: '', limite: 0, campanha_id: campId, assunto_snapshot: String(configAtual.assunto || ''), mensagem_texto_snapshot: String(configAtual.mensagem_texto || configAtual.mensagem || '') }, binary }];
  }

  return [{ json: { tipo: 'responder', status: 'erro', mensagem: 'Ação inválida.' } }];
} catch (error) {
  return [{ json: { tipo: 'responder', status: 'erro', mensagem: String(error.message || error) } }];
}

