function escapeHtml(value) {
  return String(value || '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}
function htmlToText(value) {
  return String(value || '')
    .replace(/^\uFEFF/, '')
    .replace(/<br\s*\/?\s*>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<p[^>]*>/gi, '')
    .replace(/<[^>]+>/g, '')
    .replaceAll('&nbsp;', ' ')
    .replaceAll('&lt;', '<')
    .replaceAll('&gt;', '>')
    .replaceAll('&amp;', '&')
    .replaceAll('&quot;', '"')
    .trim();
}
function textToHtml(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  return text.split(/\n{2,}/).map(paragrafo => '<p>' + escapeHtml(paragrafo).replace(/\n/g, '<br>') + '</p>').join('\n');
}
