const fs = require('fs');
const filaPath = '/files/queue.json';
const enviadosPath = '/files/sent_campaigns.json';

function readJson(path, fallback) {
  try { return JSON.parse(fs.readFileSync(path, 'utf8').replace(/^\uFEFF/, '')); } catch { return fallback; }
}
function writeJson(path, value) { fs.writeFileSync(path, JSON.stringify(value, null, 2), 'utf8'); }
function dataDepois(valor, unidade){ const ms = (String(unidade)==='minutos' ? Number(valor)*60*1000 : Number(valor)*60*60*1000); return new Date(Date.now() + (ms||60*60*1000)).toISOString(); }
function filtrarJaEnviados(contatos, campId){ const store=readJson(enviadosPath,{}); const emails=store[campId]?.emails||{}; return contatos.filter(c=>!emails[String(c.email||'').trim().toLowerCase()]); }
function safeName(name) { return String(name || 'anexo.bin').replace(/[^a-zA-Z0-9._-]+/g, '_').slice(0, 120) || 'anexo.bin'; }
async function anexosParaBinary(anexos) {
  const binary = {};
  let i = 1;
  for (const anexo of (Array.isArray(anexos) ? anexos : [])) {
    const data = String(anexo?.data || '').replace(/^data:.*?;base64,/, '');
    if (!data) continue;
    const fileName = safeName(anexo.fileName || `anexo_${i}.bin`);
    const mimeType = String(anexo.mimeType || 'application/octet-stream');
    const buffer = Buffer.from(data, 'base64');
    binary[`anexo_${i}`] = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);
    i++;
  }
  return binary;
}

const fila = Array.isArray(readJson(filaPath, [])) ? readJson(filaPath, []) : [];
const agora = new Date();
const saida = [];
const novaFila = [];

for (const campanha of fila) {
  const proxima = campanha.proxima_execucao ? new Date(campanha.proxima_execucao) : new Date(0);
  const contatos = Array.isArray(campanha.contatos) ? campanha.contatos : [];
  if (!contatos.length) continue;

  if (saida.length === 0 && proxima <= agora) {
    const campId = campanha.campanha_id || '';
    const contatosFiltrados = campId ? filtrarJaEnviados(contatos, campId) : contatos;
    if (!contatosFiltrados.length) continue;
    const qtd = Math.max(1, Number(campanha.lote_quantidade || contatosFiltrados.length || 50));
    const lote = contatosFiltrados.slice(0, qtd);
    const restantes = contatosFiltrados.slice(qtd);
    const binary = await anexosParaBinary.call(this, campanha.anexos_base64 || []);
    saida.push({
      json: {
        tipo: 'enviar',
        modo: 'direto',
        origem: 'fila_parcelada',
        campanha_id: campanha.campanha_id || '',
        responder: false,
        destinatarios_diretos: lote,
