        limite: 0,
        assunto_snapshot: campanha.assunto_snapshot || '',
        mensagem_texto_snapshot: campanha.mensagem_texto_snapshot || ''
      },
      binary
    });
    if (restantes.length) {
      campanha.contatos = restantes;
      campanha.proxima_execucao = dataDepois(campanha.intervalo_valor || campanha.intervalo_horas || 12, campanha.intervalo_unidade || 'horas');
      novaFila.push(campanha);
    }
  } else {
    novaFila.push(campanha);
  }
}

writeJson(filaPath, novaFila);
return saida;
